// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 500000

// Define the structure for a tree node
typedef struct Node {
    int supervisor;
    int club;
    struct Node* children;
} Node;

// Function to create a new tree node
Node* createNode(int supervisor, int club) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->supervisor = supervisor;
    node->club = club;
    node->children = NULL;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    child->supervisor = node->club;
    if (node->children == NULL) {
        node->children = child;
    } else {
        Node* current = node->children;
        while (current->children != NULL) {
            current = current->children;
        }
        current->children = child;
    }
}

// Function to count the number of introduces for a node
int countIntroduces(Node* node) {
    int count = 0;
    if (node->children != NULL) {
        Node* current = node->children;
        while (current != NULL) {
            count += countIntroduces(current);
            current = current->children;
        }
    }
    // Count the introduces for the current node
    if (node->supervisor != -1) {
        Node* supervisor = node->supervisor;
        if (supervisor->club == node->club) {
            count++;
        }
    }
    return count;
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int supervisors[N - 1];
    for (int i = 0; i < N - 1; i++) {
        scanf("%d", &supervisors[i]);
    }
    int clubs[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &clubs[i]);
    }
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(-1, clubs[i]);
    }
    for (int i = 1; i < N; i++) {
        addChild(nodes[supervisors[i - 1]], nodes[i]);
    }
    int ans = countIntroduces(nodes[0]);
    printf("%d\n", ans);
    for (int i = 0; i < Q; i++) {
        int X;
        scanf("%d", &X);
        int employee = i % N;
        int newClub = (X + ans) % N;
        nodes[employee]->club = newClub;
        ans = countIntroduces(nodes[0]);
        printf("%d\n", ans);
    }
    return 0;
}

