public class Main {
    static class Node {
        int supervisor;
        int club;
        ArrayList<Node> children;
        public Node(int supervisor, int club) {
            this.supervisor = supervisor;
            this.club = club;
            this.children = new ArrayList<>();
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        int[] supervisors = new int[N - 1];
        for (int i = 0; i < N - 1; i++) {
            supervisors[i] = scanner.nextInt();
        }
        int[] clubs = new int[N];
        for (int i = 0; i < N; i++) {
            clubs[i] = scanner.nextInt();
        }
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(-1, clubs[i]);
        }
        for (int i = 1; i < N; i++) {
            nodes[supervisors[i - 1]].children.add(nodes[i]);
        }
        int ans = countIntroduces(nodes[0]);
        System.out.println(ans);
        for (int i = 0; i < Q; i++) {
            int X = scanner.nextInt();
            int employee = i % N;
            int newClub = (X + ans) % N;
            nodes[employee].club = newClub;
            ans = countIntroduces(nodes[0]);
            System.out.println(ans);
        }
    }
    public static int countIntroduces(Node node) {
        int count = 0;
        if (!node.children.isEmpty()) {
            for (Node child : node.children) {
                count += countIntroduces(child);
            }
        }
        // Count the introduces for the current node
        if (node.supervisor != -1) {
            Node supervisor = node;
            if (supervisor.club == node.club) {
                count++;
            }
        }
        return count;
    }
}

